#include "bolun/kernel.h"
#include <string.h>
int bolun_virtual_alloc(int pid,uintptr_t va,size_t bytes,uint32_t flags){ if(pid<=0||pid>=BOLUN_MAX_PROCESSES) return -1; bolun_process_t *p=&g_kernel.processes[pid]; size_t pages=(bytes+BOLUN_PAGE_SIZE-1)/BOLUN_PAGE_SIZE; if(p->page_count+pages>128) return -2; for(size_t i=0;i<pages;i++){ p->pages[p->page_count++]=(bolun_page_t){.va=va+i*BOLUN_PAGE_SIZE,.pa=0,.flags=flags,.refs=1,.cow=false,.present=false}; } return 0; }
int bolun_virtual_free(int pid,uintptr_t va,size_t bytes){ if(pid<=0||pid>=BOLUN_MAX_PROCESSES) return -1; bolun_process_t *p=&g_kernel.processes[pid]; uintptr_t end=va+bytes; size_t w=0; for(size_t i=0;i<p->page_count;i++){ uintptr_t a=p->pages[i].va; if(a>=va&&a<end) continue; p->pages[w++]=p->pages[i]; } p->page_count=w; return 0; }
int bolun_page_fault(int pid,uintptr_t va,bool write){ if(pid<=0||pid>=BOLUN_MAX_PROCESSES) return -1; bolun_process_t *p=&g_kernel.processes[pid]; uintptr_t base=va & ~(uintptr_t)(BOLUN_PAGE_SIZE-1); for(size_t i=0;i<p->page_count;i++) if(p->pages[i].va==base){ if(write && p->pages[i].cow){ p->pages[i].cow=false; p->pages[i].refs=1; } p->pages[i].present=true; p->pages[i].pa=(uintptr_t)(pid*0x100000+i*BOLUN_PAGE_SIZE); return 0; } return -2; }
